function solve(nums, queries) {
    const MOD = 10**9 + 7;
    const n = nums.length;
    const xorResult = 0;

    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            nums[idx] = (nums[idx] * vi) % MOD;
            idx += ki;
        }
    }

    let xor = 0;
    for (const num of nums) {
        xor ^= num;
    }

    return xor;
}
